script.text:

function init$SalaryTransactionDefinition(f) {f._controlFocus = f.getItem('stt');}        
function active$SalaryTransactionDefinition(f) {
  f.add_onResponseComplete(on$SalaryTransactionDefinition$ResponseComplete);
  setUnitInformation(f);
}
function close$SalaryTransactionDefinition(f) {try {f.remove_onResponseComplete(on$SalaryTransactionDefinition$ResponseComplete);} catch (ex) {}}
function setUnitInformation(f) {
  if (f._action == 'New') f.setItemValues('ma_dvcs, ten_dvcs%l', [f._unitCode, f._unitName]);
}
function onChangeSalaryTransactionDefinition$Dept(o) {
  var f = o.parentForm;
  f.request('Department', 'Department', ['ma_bp']);
}
function on$SalaryTransactionDefinition$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Department':
      f.setItemValue('ma_bp_phi', result[0].Value);
      f.live(f.getItem('ma_bp_phi'));
      break;
    default:
      break;
  }
}
